  on(event: '*', listener: (event: string, ...args: any[]) => void): this;
  on(event: string, listener: (...args: any[]) => void): this {
    if (!this._listeners.has(event)) {
      this._listeners.set(event, new Set());
    }
    this._listeners.get(event)!.add(listener);
    return this;
  }

  /**
   * Register a one-time event listener.
   * The listener is automatically removed after its first invocation.
   */
  once<K extends keyof Events>(event: K, listener: (...args: Events[K]) => void): this;
  once(event: '*', listener: (event: string, ...args: any[]) => void): this;
  once(event: string, listener: (...args: any[]) => void): this {
    const wrapper = (...args: any[]) => {
      this.off(event as any, wrapper);
      listener(...args);
    };
    this._onceWrappers.set(listener, wrapper);
    return this.on(event as any, wrapper);
  }

  /**
   * Remove a previously registered event listener.
   * Also removes listeners registered via once().
   */
  off<K extends keyof Events>(event: K, listener: (...args: Events[K]) => void): this;
  off(event: '*', listener: (event: string, ...args: any[]) => void): this;
  off(event: string, listener: (...args: any[]) => void): this {
    const listeners = this._listeners.get(event);
    if (!listeners) return this;

    // Resolve the actual registered function (handle once wrappers)
    const target = this._onceWrappers.get(listener) ?? listener;
    listeners.delete(target);
    this._onceWrappers.delete(listener);

    if (listeners.size === 0) {
      this._listeners.delete(event);
    }

    return this;
  }

  /**
   * Emit an event, invoking all registered listeners with the provided arguments.
   * Wildcard ('*') listeners are also called with the event name and arguments.
   *
   * Each listener runs in its own try/catch — one listener failing does not
   * prevent the remaining listeners from executing.
   *
   * @returns true if at least one listener (specific or wildcard) was invoked.
   */
  emit<K extends keyof Events>(event: K, ...args: Events[K]): boolean {
    const eventKey = event as string;
    let hasListeners = false;

    // Snapshot listeners so mutations during emission (e.g. off/once) don't skip items
    const invoke = (fns: Set<(...args: any[]) => void>, ...callArgs: any[]) => {
      const snapshot = Array.from(fns);
      for (const fn of snapshot) {
        try {
          fn(...callArgs);
        } catch {
          // Swallow — one listener failing does not stop others
        }
      }
    };

