    if (specific) {
      hasListeners = true;
      invoke(specific, ...args);
    }

    const wildcard = this._listeners.get('*');
    if (wildcard) {
      hasListeners = true;
      invoke(wildcard, event, ...args);
    }

    return hasListeners;
  }

